window.__QUIZ_DATA__=[{"id":"theory>Geography>2023>1>a","subject":"Geography","year":"2023","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Identify five problems affecting industrial growth in developing countries.","images":[],"marking_scheme":"-Infrastructure Deficiency: Insufficient infrastructure, including inadequate transportation networks, power shortages, and limited access to water and sanitation facilities, hampers industrial growth in developing countries. The lack of reliable infrastructure makes it challenging to establish and expand industries.  -Limited Access to Capital: Many developing countries face challenges in accessing capital for industrial development. Limited availability of loans, high interest rates, and lack of venture capital impede the growth of industries, especially for small and medium-sized enterprises (SMEs).  -Poor Governance and Corruption: Weak governance structures, widespread corruption, and bureaucratic inefficiencies create an unfavorable business environment. These issues lead to uncertainty, lack of transparency, and barriers to entry for industries, discouraging both domestic and foreign investments.  -Inadequate Skilled Workforce: Developing countries often face a shortage of skilled labor, particularly in specialized industries. Insufficient access to quality education and vocational training programs limit the availability of skilled workers required for industrial growth.  -Limited Technological Advancements: Many developing countries struggle to keep pace with technological advancements due to limited research and development capabilities, inadequate access to technology, and low adoption rates. The absence of technological innovation inhibits industrial growth and competitiveness.  -Weak Regulatory Frameworks: Inadequate regulations, cumbersome bureaucratic processes, and ambiguous legal frameworks pose significant challenges for industries in developing countries. Unclear property rights, weak intellectual property protection, and excessive red tape hinder investment and growth.  -Inadequate Market Integration: Insufficient integration into regional and global markets restricts the growth potential of industries in developing countries. Trade barriers, protectionist policies, and limited access to international markets limit export opportunities and hinder industrial expansion.  -Environmental Challenges: Developing countries often face environmental issues, including pollution, deforestation, and inadequate waste management systems. These challenges not only impact the well-being of the population but also pose obstacles to sustainable industrial development and investment.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2023>1>b","subject":"Geography","year":"2023","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Suggest five measures that can promote the growth of industries in developing countries.","images":[],"marking_scheme":"-Infrastructure Development: Investing in robust infrastructure, including transportation networks, power grids, and telecommunications systems, creates an enabling environment for industries to thrive. It improves connectivity, reduces logistics costs, and attracts investment.  -Access to Finance: Enhancing access to finance for small and medium-sized enterprises (SMEs) through microcredit schemes, venture capital funds, and government-backed loan programs enables entrepreneurs to start and expand businesses, driving industrial growth.  -Skill Development and Education: Investing in education and skill development programs ensures a competent workforce capable of meeting the demands of evolving industries. Vocational training, technical education, and entrepreneurship programs equip individuals with the necessary skills for employment and entrepreneurship.  -Regulatory Reforms: Implementing business-friendly policies, reducing bureaucratic hurdles, and streamlining regulations can attract investment and foster a favorable business climate. Simplifying licensing procedures, reducing red tape, and promoting ease of doing business encourages industry growth.  -Research and Development Support: Encouraging research and development activities by providing incentives, grants, and tax breaks stimulates innovation and technological advancements. Collaborations between industries, universities, and research institutions facilitate knowledge transfer and foster innovation-driven industries.  -Export Promotion: Supporting export-oriented industries through trade policies, market access initiatives, and export promotion agencies can enhance competitiveness in the global market. Providing export incentives, trade facilitation measures, and assistance with quality standards can boost industrial growth.  -Investment in Renewable Energy: Developing countries can promote the growth of industries by investing in renewable energy sources such as solar, wind, and hydroelectric power. This not only ensures sustainable industrial development but also reduces dependence on fossil fuels, mitigating environmental impacts.  -Strengthening Institutions: Building strong institutions and improving governance frameworks create a stable and transparent business environment. Enhancing transparency, combating corruption, and strengthening legal frameworks protect investments and promote industrial growth.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2023>2>a","subject":"Geography","year":"2023","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Outline five characteristics of rural settlements in Tropical Africa","images":[],"marking_scheme":"-Sparse Population: Rural settlements in tropical Africa tend to have a relatively low population density compared to urban areas. The population is often scattered across vast areas of land, with larger distances between individual households or villages.  -Agricultural economy: Rural settlements in tropical Africa are predominantly agrarian, with agriculture being the primary economic activity. People rely on subsistence farming, livestock rearing, and small-scale agricultural production for their livelihoods.  -Traditional housing: Rural settlements often have traditional housing structures made of locally available materials such as mud, thatch, or wood. These structures are designed to suit the local climate and cultural preferences.  -Limited infrastructure: Rural settlements in tropical Africa often lack adequate infrastructure compared to urban areas. Basic amenities like electricity, clean water supply, healthcare facilities, and transportation networks may be limited or lacking altogether.  -Close-knit communities: Rural settlements typically have close-knit communities with strong social ties and communal values. People often live in extended family units and engage in collective activities such as farming, celebrations, and community decision-making.  -Limited access to services: Due to their remote locations, rural settlements may have limited access to essential services such as education, healthcare, and government institutions. Access to quality education and healthcare facilities may be inadequate, resulting in challenges for rural residents.  -Traditional social systems: Rural settlements in tropical Africa often have traditional social structures and systems that play a significant role in community life. This includes kinship systems, communal decision-making processes, and the influence of local chiefs or elders in governance and dispute resolution.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2023>2>b","subject":"Geography","year":"2023","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"In what five ways does rural settlement depend on urban settlement?","images":[],"marking_scheme":"-Technology and information: Urban areas often serve as centers of technological advancement and information dissemination. Rural settlements rely on urban areas for access to modern technologies, internet connectivity, and information resources that can enhance agricultural practices, education, healthcare, and overall development.  -Education and healthcare: Urban areas typically have better educational and healthcare facilities compared to rural settlements. Rural residents often depend on urban schools, colleges, and universities for higher education, and they may travel to urban centers to access specialized healthcare services.  -Market access: Rural settlements rely on urban settlements as market centers for selling their agricultural produce and acquiring necessary goods and services that are not available locally. Urban centers act as economic hubs where rural farmers can sell their surplus produce and purchase items they cannot produce themselves.  -Supply of goods and services: Rural settlements depend on urban settlements for the supply of goods and services that are not available in rural areas. This includes items like machinery, fertilizers, construction materials, healthcare services, and educational resources.  -Employment opportunities: Many rural inhabitants depend on urban settlements for employment opportunities. People may migrate from rural areas to urban areas in search of better job prospects and higher wages, particularly in non-agricultural sectors such as manufacturing, construction, and services.  -Transportation and logistics: Urban areas provide transportation networks and logistics services that facilitate the movement of goods and people between rural and urban settlements. Rural communities rely on urban transportation systems for the shipment of agricultural produce, the transportation of essential goods, and the movement of people.  -Infrastructure development: Urban areas are often the hubs of infrastructure development. Rural settlements rely on urban centers for the construction and maintenance of roads, bridges, electricity grids, telecommunications networks, and other vital infrastructure.  -Government services and administration: Rural settlements often depend on urban settlements for government services and administration. Government offices, educational institutions, healthcare facilities, and other essential services are usually concentrated in urban areas. Rural residents may need to travel to urban centers to access these services or engage with government institutions","marks":"10","difficulty":"3"},{"id":"theory>Geography>2023>3>a","subject":"Geography","year":"2023","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Describe rail transportation in Tropical Africa under the following headings:  four advantages;","images":[],"marking_scheme":"-Efficient Movement of Goods: Rail transportation allows for the efficient movement of goods across long distances. It can accommodate large quantities of cargo, making it an ideal mode of transport for industries such as agriculture, mining, and manufacturing in tropical Africa. This efficiency helps stimulate trade and economic growth.  -Reduced Congestion: Compared to road transportation, rail systems help alleviate congestion on major highways. By diverting a significant portion of freight traffic to rail, the congestion on roads is reduced, resulting in smoother traffic flow, decreased travel times, and improved road safety.  -Lower Environmental Impact: Rail transportation is more environmentally friendly compared to road transport. Trains emit less carbon dioxide per ton of freight compared to trucks, reducing greenhouse gas emissions and air pollution. This advantage is crucial for tropical Africa's sustainability efforts and can contribute to mitigating climate change impacts.  -Enhanced Connectivity: Rail networks provide enhanced connectivity by linking remote areas and cities, facilitating economic integration and regional development. They enable access to markets, resources, and employment opportunities, boosting trade, tourism, and economic activities across tropical Africa.  -Increased Accessibility: Rail systems provide reliable and accessible transportation for both passengers and goods. They offer a cost-effective means of travel, making it easier for people to commute between cities and towns, visit tourist destinations, and access essential services such as healthcare and education. This accessibility helps bridge the gap between rural and urban areas.  -Job Creation: Developing rail infrastructure in tropical Africa generates employment opportunities in various sectors. From construction and maintenance to operation and management, rail projects create jobs for engineers, technicians, drivers, station staff, and support personnel. This job creation contributes to economic development and poverty reduction.  -Long-term Cost Savings: While initial investments in rail infrastructure may be significant, in the long run, rail transport can be cost-effective. Railways have lower operating costs compared to road transport due to lower fuel consumption, reduced vehicle maintenance, and decreased road damage. These cost savings can be beneficial for both businesses and governments.","marks":"8","difficulty":"3"},{"id":"theory>Geography>2023>3>b","subject":"Geography","year":"2023","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Describe rail transportation in Tropical Africa under the following headings:  three problems affecting rail transportation,","images":[],"marking_scheme":"-Insufficient Infrastructure: Many countries in tropical Africa have outdated and inadequate rail infrastructure. The existing rail networks often suffer from poor maintenance, outdated technology, and insufficient capacity. This results in slower speeds, frequent breakdowns, and limited connectivity, hindering the smooth movement of goods and passengers.  -Funding Constraints: Lack of adequate funding is a major challenge for rail projects in tropical Africa. Limited financial resources lead to delays in infrastructure upgrades, repairs, and expansion, hampering the overall efficiency of rail transportation.  -Inadequate Maintenance: Due to financial constraints and lack of technical expertise, rail infrastructure in tropical Africa often suffers from inadequate maintenance. This results in deteriorating tracks, bridges, and signaling systems, leading to frequent disruptions, delays, and safety concerns.  -Lack of Interconnectivity: Many rail networks in tropical Africa suffer from a lack of interconnectivity, limiting their reach and effectiveness. Incomplete or fragmented rail systems make it challenging to transport goods seamlessly across different regions, hindering economic integration and trade.  -Inefficient Operations: Inefficient operations and management practices contribute to the problems facing rail transportation in tropical Africa. Factors such as outdated technology, inadequate training of staff, and suboptimal scheduling and coordination lead to delays, inefficiencies, and reduced service quality.  -Insecurity: Rail transportation in tropical Africa often faces security challenges such as vandalism, theft, and sabotage. These incidents not only disrupt operations but also pose risks to the safety of passengers and cargo.","marks":"6","difficulty":"3"},{"id":"theory>Geography>2023>3>c","subject":"Geography","year":"2023","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Describe rail transportation in Tropical Africa under the following headings:  one solution to each of the problems stated in 3(b).","images":[],"marking_scheme":"-Insufficient Infrastructure: Increased investment in rail infrastructure by seeking partnerships with international organizations, private sector entities, and foreign investors can provide the necessary funding for infrastructure upgrades, expansion, and modernization, thereby improving the capacity and quality of rail networks.  -Funding Constraints: Governments can offer incentives and create a conducive business environment to encourage private sector participation.  -Inadequate Maintenance: Government should establish a dedicated maintenance fund for rail infrastructure, ensuring a regular and sufficient budget allocation for maintenance activities and also train and employ skilled maintenance personnel.  -Lack of Interconnectivity: Improved coordination and planning are required to enhance interconnectivity between different rail lines and modes of transport.  -Inefficient Operations: Implementing modern management practices, training programs, and technological upgrades can address these issues.  -Insecurity: Strengthening security measures, implementing surveillance systems, and increasing law enforcement presence can help mitigate these risks","marks":"6","difficulty":"3"},{"id":"theory>Geography>2023>4>a","subject":"Geography","year":"2023","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"What is internal trade?","images":[],"marking_scheme":"Internal trade refers to the exchange of goods, services, and resources within the boundaries of a particular country or region. It involves commercial transactions and economic activities conducted between individuals, businesses, or entities located within the same country or geographic area.  OR  Internal trade refers to the buying and selling of goods and services within the geographical boundaries of a country. It involves the exchange of goods and services between different regions, states or cities within the country.","marks":"2","difficulty":"1"},{"id":"theory>Geography>2023>4>b","subject":"Geography","year":"2023","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRADE","question":"Outline five problems limiting internal trade in Nigeria.","images":[],"marking_scheme":"-Poor Trade Facilitation: Inefficient trade facilitation processes, including cumbersome documentation requirements, lack of harmonization in trade regulations across states, and delays in clearing goods at ports and borders, increase transaction costs and hinder internal trade.  -High Cost of Finance: Limited access to affordable credit and high interest rates make it difficult for small and medium-sized enterprises (SMEs) to access capital for business expansion and investment in internal trade.  -Poor infrastructure: Nigeria's poor road network, insufficient transport systems, and inadequate storage facilities make it difficult to move goods from one location to another, resulting in delays, high transportation costs, and damage to goods.  -Inconsistent Policies and Regulations: Frequent changes in policies and regulations at various levels of government create uncertainty and hamper trade activities. Inconsistent policies can result in confusion, compliance difficulties, and discourage investment in the country.  -Multiple taxation: The multiplicity of taxes imposed on traders, including local government levies, state taxes, and federal duties, makes trading in Nigeria very expensive, reducing profitability for traders.  -Corruption: Bribery and extortion of traders by government officials, security forces, and market leaders have been a persistent problem in Nigeria, discouraging many from engaging in formal internal trade.  -Insecurity: Insurgency, banditry, and other forms of violence in different parts of Nigeria have adversely affected internal trade, discouraging traders from entering certain regions, causing loss of life and property, and disrupting supply chains.  -Multiple Checkpoints and Roadblocks: Excessive checkpoints, roadblocks, and extortion by security personnel pose significant challenges to internal trade. These checkpoints cause delays, corruption, and raise the cost of doing business.  -Inefficient Customs Procedures: Cumbersome customs procedures, including excessive paperwork and delays in clearing goods, hinder the smooth flow of trade within Nigeria. This leads to increased transaction costs and negatively affects the competitiveness of local businesses.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2023>4>c","subject":"Geography","year":"2023","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRADE","question":"Identify four importance of internal trade in Nigeria","images":[],"marking_scheme":"-Revenue Generation: Internal trade generates revenue for the government through taxes, duties, and other levies imposed on trade activities. These revenues can be used to fund infrastructure development, social welfare programs, and other public services, contributing to the overall socio-economic development of the country  -Social Integration: Internal trade promotes social integration by connecting people from different regions and cultures within Nigeria. It facilitates the exchange of ideas, knowledge, and cultural practices, fostering unity and a sense of national identity. It also helps to reduce regional disparities and promotes social cohesion.  -Diversification of Economy: Internal trade promotes the diversification of the Nigerian economy. It allows for the exchange of a wide range of goods and services, which encourages the development of various sectors, such as agriculture, manufacturing, and services. This diversification reduces dependence on a single industry, making the economy more resilient to external shocks.  -Encourages Investment: A vibrant internal trade environment attracts domestic and foreign investment. When businesses have access to a large and diverse market, they are more likely to invest in expanding their operations, building infrastructure, and creating employment opportunities. This, in turn, drives economic growth and development.  -Economic growth: Internal trade drives economic growth by promoting the exchange of goods and services between regions, stimulating competition, encouraging innovation, and creating jobs.  -Market Efficiency: Internal trade helps to create a more efficient market by facilitating the movement of goods from areas of surplus to areas of demand. This ensures that products are available at competitive prices throughout the country, reducing regional disparities and ensuring optimal allocation of resources.  -Poverty reduction: Internal trade provides income and employment opportunities for many Nigerians, particularly those in the informal sector, helping to reduce poverty in the country.  -Regional integration: Internal trade promotes regional integration by encouraging the exchange of goods and services between different regions, enhancing economic cooperation and social cohesion.  -Enhanced food security: Internal trade promotes access to food in different regions, ensuring that people have enough food to eat, no matter where they live. This is particularly important in times of food shortages or when certain foods are unavailable in a particular region.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2023>5>a>i","subject":"Geography","year":"2023","type":"Theory","sub_label":"i","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of Nigeria. On the map, locate and name:  the Sudan savanna belt.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"3","difficulty":"2"},{"id":"theory>Geography>2023>5>a>ii","subject":"Geography","year":"2023","type":"Theory","sub_label":"ii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of Nigeria. On the map, locate and name:  the Tropical rainforest belt","images":["data:image/png;base64,"],"marking_scheme":"","marks":"2","difficulty":"2"},{"id":"theory>Geography>2023>5>a>iii","subject":"Geography","year":"2023","type":"Theory","sub_label":"iii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of Nigeria. On the map, locate and name:  one town in 5(a)(ii).","images":["data:image/png;base64,"],"marking_scheme":"","marks":"1","difficulty":"2"},{"id":"theory>Geography>2023>5>b","subject":"Geography","year":"2023","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Identify four characteristics of the Tropical rainforest in Nigeria.","images":[],"marking_scheme":"-It has tall trees with buttress and evergreen  -presence of little undergrowth due to canopies  -plant species are not in pure stand  -it has numerous heterogenous species e.g Mahogamy, Iroko","marks":"4","difficulty":"2"},{"id":"theory>Geography>2023>5>c","subject":"Geography","year":"2023","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"Outline five economic importance of the Tropical rainforest to Nigeria","images":[],"marking_scheme":"-it provide tropical hard wood like Iroko  -Lumbering of these trees provide employment  -Forest provide wood as source of fuel  -Farming activities especially the cultivation of tree crops  -It also provide medicinal herbs","marks":"10","difficulty":"2"},{"id":"theory>Geography>2023>6>a>i","subject":"Geography","year":"2023","type":"Theory","sub_label":"i","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of Nigeria.  On the map, locate and name: River Benue.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"3","difficulty":"2"},{"id":"theory>Geography>2023>6>a>ii","subject":"Geography","year":"2023","type":"Theory","sub_label":"ii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of Nigeria.  On the map, locate and name: River Sokoto","images":["data:image/png;base64,"],"marking_scheme":"","marks":"2","difficulty":"2"},{"id":"theory>Geography>2023>6>a>iii","subject":"Geography","year":"2023","type":"Theory","sub_label":"iii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of Nigeria.  On the map, locate and name: Makurdi.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"1","difficulty":"2"},{"id":"theory>Geography>2023>6>b","subject":"Geography","year":"2023","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Outline three characteristics of rivers in Nigeria","images":[],"marking_scheme":"-presenceof rapids and cataracts  -The volume of the river changes with seasons  -short course with high speed","marks":"6","difficulty":"1"},{"id":"theory>Geography>2023>6>c","subject":"Geography","year":"2023","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"In what four ways are rivers useful in Nigeria?","images":[],"marking_scheme":"-medium of transportation  -Generation of Hydro-electric power  -provision of employment e.g fishing  -domestic uses e.g bathing, cooking.","marks":"8","difficulty":"1"}];